import React from "react";
import { Link } from "react-router-dom";

function Navbar() {
  return (
    <nav style={styles.nav}>
      <h2>ElectroStore</h2>
      <ul style={styles.menu}>
        <li><Link to="/">Home</Link></li>
        <li><Link to="/category/phones">Phones</Link></li>
        <li><Link to="/category/headphones">Headphones</Link></li>
        <li><Link to="/category/ps5">PS5</Link></li>
        <li><Link to="/cart">Cart</Link></li>
      </ul>
    </nav>
  );
}

const styles = {
  nav: { display: "flex", justifyContent: "space-between", padding: "10px 20px", background: "#222", color: "#fff" },
  menu: { display: "flex", listStyle: "none", gap: "20px" }
};

export default Navbar;
